 1	import * as React from 'react';
 2	import { PrometheusMultilineUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-multi-utilization-item';
 3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 4	import { humanizeDecimalBytesPerSec } from '@odf/shared/utils';
 5	import { UtilizationDurationDropdown } from '@openshift-console/dynamic-plugin-sdk-internal';
 6	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 7	import { NFS_HOST_THROUGHPUT_TOTAL, NFSDashboardQuery } from '../../../queries';
 8	
 9	export const ThroughputCard: React.FC = () => {
10	  const { t } = useCustomTranslation();
11	
12	  return (
13	    <Card data-test="nfs-throughput-card">
14	      <CardHeader
15	        actions={{
16	          actions: <UtilizationDurationDropdown />,
17	          hasNoOffset: false,
18	          className: undefined,
19	        }}
20	      >
21	        <CardTitle>{t('Performance')}</CardTitle>
22	      </CardHeader>
23	      <CardBody>
24	        <PrometheusMultilineUtilizationItem
25	          title={t('Server throughput')}
26	          queries={[
27	            NFS_HOST_THROUGHPUT_TOTAL[NFSDashboardQuery.HOST_READ_TOTAL],
28	            NFS_HOST_THROUGHPUT_TOTAL[NFSDashboardQuery.HOST_WRITE_TOTAL],
29	          ]}
30	          humanizeValue={humanizeDecimalBytesPerSec}
31	          chartType="stacked-area"
32	        />
33	      </CardBody>
34	    </Card>
35	  );
36	};

